final:
module top_module(
    input clk,
    input [3:0] parallel_in,
    input serial_in,
    output serial_out
);reg [3:0] shift_reg;

always @(posedge clk) begin
    if (parallel_in) begin
        shift_reg <= parallel_in;
    end else begin
        shift_reg <= {shift_reg[2:0], serial_in};
    end
end

assign serial_out = shift_reg[0];

endmodule
